import{_ as a,c as o,o as i,ae as t}from"./chunks/framework.Bw7rlmih.js";const h=JSON.parse('{"title":"CP-016: Governance, Approvals, and Audit","description":"","frontmatter":{},"headers":[],"relativePath":"control-plane/atomic/CP-016-governance-approvals-and-audit.md","filePath":"control-plane/atomic/CP-016-governance-approvals-and-audit.md"}'),l={name:"control-plane/atomic/CP-016-governance-approvals-and-audit.md"};function r(c,e,n,d,s,p){return i(),o("div",null,e[0]||(e[0]=[t('<h1 id="cp-016-governance-approvals-and-audit" tabindex="-1">CP-016: Governance, Approvals, and Audit <a class="header-anchor" href="#cp-016-governance-approvals-and-audit" aria-label="Permalink to &quot;CP-016: Governance, Approvals, and Audit&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Define governance controls for protected scopes and environments.</p><h2 id="inputs-outputs" tabindex="-1">Inputs / Outputs <a class="header-anchor" href="#inputs-outputs" aria-label="Permalink to &quot;Inputs / Outputs&quot;">​</a></h2><ul><li>Input: change request (publish, promote, override).</li><li>Output: approved/rejected decision and immutable audit trail.</li></ul><h2 id="public-interfaces" tabindex="-1">Public Interfaces <a class="header-anchor" href="#public-interfaces" aria-label="Permalink to &quot;Public Interfaces&quot;">​</a></h2><ul><li><code>POST /v1/approvals/requests</code></li><li><code>POST /v1/approvals/requests/{id}/approve</code></li><li><code>POST /v1/approvals/requests/{id}/reject</code></li><li><code>GET /v1/audit/events</code></li></ul><h2 id="data-contracts" tabindex="-1">Data Contracts <a class="header-anchor" href="#data-contracts" aria-label="Permalink to &quot;Data Contracts&quot;">​</a></h2><p>Approval request fields:</p><ul><li><code>requestId</code></li><li><code>scope</code></li><li><code>action</code></li><li><code>targetRef</code></li><li><code>requestedBy</code></li><li><code>requiredApprovers</code></li><li><code>status</code></li></ul><p>Audit event fields:</p><ul><li><code>auditId</code></li><li><code>occurredAt</code></li><li><code>actor</code></li><li><code>scope</code></li><li><code>action</code></li><li><code>decision</code></li><li><code>reason</code></li><li><code>relatedRefs[]</code></li></ul><h2 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h2><ul><li>Protected scopes require approval before reference movement.</li><li>Approver cannot self-approve when policy forbids it.</li><li>Audit entries are immutable and append-only.</li></ul><h2 id="failure-modes" tabindex="-1">Failure Modes <a class="header-anchor" href="#failure-modes" aria-label="Permalink to &quot;Failure Modes&quot;">​</a></h2><ul><li><code>403 approval_required</code></li><li><code>403 self_approval_not_allowed</code></li><li><code>409 approval_request_expired</code></li></ul><h2 id="acceptance-criteria" tabindex="-1">Acceptance Criteria <a class="header-anchor" href="#acceptance-criteria" aria-label="Permalink to &quot;Acceptance Criteria&quot;">​</a></h2><ol><li>Promotion to <code>*/prod/*</code> without approval is blocked.</li><li>Approved request unblocks only exact referenced action.</li><li>Rejection reason is mandatory and queryable in audit trail.</li><li>Audit timeline reconstructs full decision chain for any promotion.</li></ol><h2 id="out-of-scope" tabindex="-1">Out of Scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of Scope&quot;">​</a></h2><ul><li>External ticketing system workflow orchestration.</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li>CP-002 authz.</li><li>CP-003 protected refs.</li><li>CP-010 events.</li></ul>',22)]))}const v=a(l,[["render",r]]);export{h as __pageData,v as default};
